import 'react-native-url-polyfill/auto';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { createClient } from '@supabase/supabase-js';
import { Post, Comment } from '../types';

const SUPABASE_URL = 'https://wyasfdpeyzdiqtppooxb.supabase.co';
const SUPABASE_KEY = 'YOUR_SUPABASE_KEY_HERE'; // Keep your key from the original file

// React Native Storage Adapter for Supabase Auth
const ExpoAdapter = {
  getItem: (key: string) => {
    return AsyncStorage.getItem(key);
  },
  setItem: (key: string, value: string) => {
    AsyncStorage.setItem(key, value);
  },
  removeItem: (key: string) => {
    AsyncStorage.removeItem(key);
  },
};

// We need to initialize the client slightly differently to handle async headers
// For this simple refactor, we initialize basic client first
const supabase = createClient(SUPABASE_URL, SUPABASE_KEY, {
  auth: {
    storage: ExpoAdapter,
    autoRefreshToken: true,
    persistSession: true,
    detectSessionInUrl: false,
  },
});

export const getSupabase = () => supabase;

// --- Helper for Shadow ID ---
// In React Native, storage is Async. We generate a memory ID first.
let cachedShadowId: string | null = null;

export const getShadowIdentity = async (): Promise<string> => {
  if (cachedShadowId) return cachedShadowId;

  try {
    let id = await AsyncStorage.getItem('shadow_user_id');
    if (!id) {
      id = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
        var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
        return v.toString(16);
      });
      await AsyncStorage.setItem('shadow_user_id', id);
    }
    cachedShadowId = id;

    // Patch the global headers dynamically
    supabase.rest.headers['x-shadow-user-id'] = id;

    return id;
  } catch (e) {
    return 'fallback-uuid';
  }
};

export const initializeAuth = async (): Promise<string> => {
  const shadowId = await getShadowIdentity();

  try {
    const { data: { session } } = await supabase.auth.getSession();
    if (session?.user) return session.user.id;

    const { data, error } = await supabase.auth.signInAnonymously();
    if (data.user) return data.user.id;

    return shadowId;
  } catch (e) {
    return shadowId;
  }
};

