  const colorScheme = useColorScheme();
  const isDark = colorScheme === 'dark';
  const [posts, setPosts] = useState<Post[]>([]);
  const [refreshing, setRefreshing] = useState(false);
  const [currentUserNickname, setCurrentUserNickname] = useState('Guest');
  const [authUserId, setAuthUserId] = useState<string | null>(null);

  // Load Nickname
  useEffect(() => {
    AsyncStorage.getItem('echo_nickname').then(name => {
      if (name) setCurrentUserNickname(name);
    });
  }, []);

  // Init Auth
  useEffect(() => {
    const init = async () => {
      const uid = await SupabaseService.initializeAuth();
      setAuthUserId(uid);
      loadPosts();
    };
    init();
  }, []);

  // Save Nickname when changed
  useEffect(() => {
    if (currentUserNickname) {
        AsyncStorage.setItem('echo_nickname', currentUserNickname);
    }
  }, [currentUserNickname]);

  const loadPosts = async () => {
    try {
      const remotePosts = await SupabaseService.fetchPosts();
      setPosts(remotePosts);
    } catch (e) {
      console.log(e);
    }
  };

  const onRefresh = useCallback(async () => {
    setRefreshing(true);
    await loadPosts();
    setRefreshing(false);
  }, []);

  const handleUserPost = async (nickname: string, content: string, tags: string[]) => {
    setCurrentUserNickname(nickname);
    // Optimistic update omitted for brevity, adding directly to DB
    if (authUserId) {
       await SupabaseService.createPost(nickname, content, tags, authUserId);
       loadPosts(); // Refresh list
    }
  };

  return (
    <SafeAreaProvider>
      <SafeAreaView className="flex-1 bg-[#FAFAFA] dark:bg-black">
        <StatusBar barStyle={isDark ? 'light-content' : 'dark-content'} />

        {/* Header */}
        <View className="px-5 py-4 bg-white/80 dark:bg-black/80 border-b border-neutral-200 dark:border-neutral-800 z-10 flex-row justify-between items-center">
           <Text className="text-xl font-bold text-black dark:text-white">Echo</Text>
           <View className="w-2 h-2 rounded-full bg-green-500" />
        </View>

        <FlatList
          data={posts}
          keyExtractor={(item) => item.id}
          contentContainerStyle={{ padding: 16, paddingBottom: 100 }}
          refreshControl={
            <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={isDark ? "#FFF" : "#000"} />
          }
          ListHeaderComponent={
            <CreatePost onPost={handleUserPost} defaultNickname={currentUserNickname} />
          }
          renderItem={({ item }) => (
            <PostCard 
               post={item} 
               isUser={item.author.userId === authUserId}
               currentUserId={authUserId}
               onDelete={(id) => SupabaseService.deletePost(SupabaseService.getSupabase(), id, authUserId).then(loadPosts)}
            />
          )}
          ListEmptyComponent={
            <View className="items-center py-20">
                <Text className="text-neutral-400">Echo is quiet...</Text>
            </View>
          }
        />
      </SafeAreaView>
    </SafeAreaProvider>
  );
}
